import React, { useState, useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

const Navbar = () => {
  const [categories, setCategories] = useState([]);
  const [showDropdown, setShowDropdown] = useState(false);
  const [loading, setLoading] = useState(true);
  const hideTimeout = useRef(null);

  const API_BASE_URL = "http://localhost:5000/api";

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/categories`);
      if (Array.isArray(res.data)) setCategories(res.data);
      else setCategories([]);
    } catch (err) {
      console.error("Navbar: Error fetching categories:", err);
      setCategories([]);
    } finally {
      setLoading(false);
    }
  };

  const handleMouseEnter = () => {
    if (hideTimeout.current) clearTimeout(hideTimeout.current);
    setShowDropdown(true);
  };

  const handleMouseLeave = () => {
    hideTimeout.current = setTimeout(() => {
      setShowDropdown(false);
    }, 250); // delay nhỏ để rê chuột xuống menu không bị mất
  };

  return (
    <nav className="bg-[#1e293b] shadow-md">
      <div className="max-w-7xl mx-auto flex justify-center py-3 px-8">
        <ul className="flex items-center justify-around gap-10 text-white font-medium text-lg">
          <li>
            <Link
              to="/"
              className="hover:text-[#f472b6] transition-colors duration-200"
            >
              Trang chủ
            </Link>
          </li>

          <li>
            <Link
              to="/product"
              className="hover:text-[#f472b6] transition-colors duration-200"
            >
              Sản phẩm
            </Link>
          </li>

          {/* DANH MỤC */}
          <li
            className="relative"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <button className="flex items-center gap-1 hover:text-[#f472b6] transition-colors duration-200 focus:outline-none">
              Danh mục <span className="text-sm">▼</span>
            </button>

            {showDropdown && (
              <div
                className="absolute top-full left-1/2 -translate-x-1/2 bg-white border border-[#e5e7eb] shadow-lg rounded-xl mt-2 w-64 z-50 animate-fadeIn"
                onMouseEnter={handleMouseEnter}
                onMouseLeave={handleMouseLeave}
              >
                {loading ? (
                  <div className="p-4 text-center text-gray-500 text-sm">
                    Đang tải danh mục...
                  </div>
                ) : categories.length === 0 ? (
                  <div className="p-4 text-center text-gray-600 text-sm">
                    Chưa có danh mục nào
                  </div>
                ) : (
                  <ul className="max-h-80 overflow-y-auto">
                    {categories.map((category) => (
                      <li key={category._id}>
                        <Link
  to={`/category/${category.slug}`}
  className="block px-4 py-2 text-gray-800 hover:bg-[#f0e2da] hover:text-[#d9467a] transition-all"
>
  {category.name}
</Link>

                      </li>
                    ))}
                    <li className="border-t border-gray-200">
                      <Link
                        to="/product"
                        className="block px-4 py-2 text-center text-[#d9467a] font-semibold hover:underline"
                      >
                        Xem tất cả sản phẩm
                      </Link>
                    </li>
                  </ul>
                )}
              </div>
            )}
          </li>

          <li>
            <Link
              to="/about"
              className="hover:text-[#f472b6] transition-colors duration-200"
            >
              Giới thiệu
            </Link>
          </li>

          <li>
            <Link
              to="/contact"
              className="hover:text-[#f472b6] transition-colors duration-200"
            >
              Liên hệ
            </Link>
          </li>
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
